using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    internal class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var document = JsonDocument.ParseValue(ref reader);
            return ReadResponseError(document.RootElement);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            WriteResponseError(writer, value);
        }

        private static ResponseError ReadResponseError(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }

            string code = null;
            string message = null;
            string target = null;
            ResponseInnerError innerError = null;
            List<ResponseError> details = null;

            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"u8))
                {
                    code = property.Value.GetString();
                }
                else if (property.NameEquals("message"u8))
                {
                    message = property.Value.GetString();
                }
                else if (property.NameEquals("target"u8))
                {
                    target = property.Value.GetString();
                }
                else if (property.NameEquals("innererror"u8))
                {
                    innerError = ReadInnerError(property.Value);
                }
                else if (property.NameEquals("details"u8))
                {
                    if (property.Value.ValueKind == JsonValueKind.Array)
                    {
                        details = new List<ResponseError>();
                        foreach (var item in property.Value.EnumerateArray())
                        {
                            details.Add(ReadResponseError(item));
                        }
                    }
                }
            }

            return new ResponseError(code, message, target, default, innerError, details);
        }

        private static ResponseInnerError ReadInnerError(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }

            string code = null;
            ResponseInnerError nested = null;

            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"u8))
                {
                    code = property.Value.GetString();
                }
